def edit_distance(a, b):
    if len(a) < len(b):
        a, b = b, a
    if not b:
        return len(a)
    prev_row = list(range(len(b) + 1))
    for i, col_val in enumerate(a, 1):
        current_row = [i]
        for j, row_val in enumerate(b, 1):
            insert_cost = prev_row[j] + 1
            delete_cost = current_row[j - 1] + 1
            substitute_cost = prev_row[j - 1] if col_val == row_val else prev_row[j - 1] + 1
            current_row.append(min(insert_cost, delete_cost, substitute_cost))
        prev_row = current_row
    return prev_row[-1]
